mapper.update:
UPDATE approvalDeputyReg
SET isActive = 'N'
WHERE deputyRegId   = #{deputyRegId}
  AND delegatorEmpId = #{empId}

UPDATE approvalDeputyReg
SET deputyEmpId = #{deputyEmpId, jdbcType=VARCHAR},
    deputyName  = #{deputyName,  jdbcType=VARCHAR},
    startDate   = TO_DATE(#{startDate, jdbcType=VARCHAR}, 'YYYY-MM-DD'),
    endDate     = TO_DATE(#{endDate,   jdbcType=VARCHAR}, 'YYYY-MM-DD'),
    reason      = #{reason,      jdbcType=VARCHAR},
    isActive    = #{isActive,    jdbcType=VARCHAR}
WHERE deputyRegId = #{deputyRegId}
  AND delegatorEmpId = #{delegatorEmpId}

mapper.select:
SELECT COUNT(*)
FROM approvalDeputyReg
WHERE delegatorEmpId = #{empId}
